+# API Reference
+
+Programmatic API for the V3 init system.
+
+## Installation
+
+```typescript
+import {
+  executeInit,
+  detectPlatform,
+  DEFAULT_INIT_OPTIONS,
+  MINIMAL_INIT_OPTIONS,
+  FULL_INIT_OPTIONS,
+  type InitOptions,
+  type InitResult,
+  type PlatformInfo,
+} from '@claude-flow/cli/init';
+```
+
+## Core Functions
+
+### executeInit
+
+Main initialization function.
+
+```typescript
+async function executeInit(options: InitOptions): Promise<InitResult>
+```
+
+**Parameters:**
+- `options: InitOptions` - Configuration options
+
+**Returns:**
+- `Promise<InitResult>` - Result with created files and errors
+
+**Example:**
+```typescript
+import { executeInit, DEFAULT_INIT_OPTIONS } from '@claude-flow/cli/init';
+
+const result = await executeInit({
+  ...DEFAULT_INIT_OPTIONS,
+  targetDir: '/path/to/project',
+  sourceBaseDir: '/path/to/claude-flow',
+  force: true,
+});
+
+if (result.success) {
+  console.log(`Created ${result.created.files.length} files`);
+  console.log(`Platform: ${result.platform.os}`);
+}
+```
+
+### detectPlatform
+
+Detect current operating system and environment.
+
+```typescript
+function detectPlatform(): PlatformInfo
+```
+
+**Returns:**
+- `PlatformInfo` - Platform detection results
+
+**Example:**
+```typescript
+import { detectPlatform } from '@claude-flow/cli/init';
+
+const platform = detectPlatform();
+console.log(`OS: ${platform.os}`);
+console.log(`Shell: ${platform.shell}`);
+console.log(`Config dir: ${platform.configDir}`);
+```
+
+## Types
+
+### InitOptions
+
+```typescript
+interface InitOptions {
+  targetDir: string;
+  sourceBaseDir?: string;
+  force: boolean;
+  interactive: boolean;
+  components: InitComponents;
+  hooks: HooksConfig;
+  skills: SkillsConfig;
+  commands: CommandsConfig;
+  agents: AgentsConfig;
+  statusline: StatuslineConfig;
+  mcp: MCPConfig;
+  runtime: RuntimeConfig;
+}
+```
+
+### InitResult
+
+```typescript
+interface InitResult {
+  success: boolean;
+  platform: PlatformInfo;
+  created: {
+    directories: string[];
+    files: string[];
+  };
+  skipped: string[];
+  errors: string[];
+  summary: {
+    skillsCount: number;
+    commandsCount: number;
+    agentsCount: number;
+    hooksEnabled: number;
+  };
+}
+```
+
+### PlatformInfo
+
+```typescript
+interface PlatformInfo {
+  os: 'windows' | 'darwin' | 'linux';
+  arch: 'x64' | 'arm64' | 'arm' | 'ia32';
+  nodeVersion: string;
+  shell: 'powershell' | 'cmd' | 'bash' | 'zsh' | 'sh';
+  homeDir: string;
+  configDir: string;
+}
+```
+
+### InitComponents
+
+```typescript
+interface InitComponents {
+  settings: boolean;
+  skills: boolean;
+  commands: boolean;
+  agents: boolean;
+  helpers: boolean;
+  statusline: boolean;
+  mcp: boolean;
+  runtime: boolean;
+}
+```
